        CONGRATULATIONS_BALLISTA_POINT_RANKING_REGISTRATION_FOR_THE_PREVIOUS   = 7666,  -- Congratulations! Ballista Point Ranking registration for the previous match has come to a close, and your final overall rank is #! You shall be presented with % and a new title.
        GOOD_SHOW_BALLISTA_POINT_RANKING_REGISTRATION_FOR_THE                  = 7667,  -- Good show! Ballista Point Ranking registration for the previous match has come to a close, and your final rank among participating [/warriors/monks/white mages/black mages/red mages/thieves/paladins/dark knights/beastmasters/bards/rangers/samurais/ninjas/dragoons/summoners/blue mage/corsairs/puppetmasters/dancers/scholars/geomancers/rune fencers] (# total) is first! You shall be presented with % and a new title.
        WELL_DONE_BALLISTA_POINT_RANKING_REGISTRATION_FOR_THE                  = 7668,  -- Well done! Ballista Point Ranking registration for the previous match has come to a close, and your final overall rank is #! In addition, your final rank among participating [/warriors/monks/white mages/black mages/red mages/thieves/paladins/dark knights/beastmasters/bards/rangers/samurais/ninjas/dragoons/summoners/blue mage/corsairs/puppetmasters/dancers/scholars/geomancers/rune fencers] (# total) is first! You shall be presented with % or %, as well as a new title.
        WHILE_OUR_RECORDS_WILL_CLEARLY_INDICATE_THAT_YOU                       = 7669,  -- While our records will clearly indicate that you were rewarded both chevrons, Ballista regulations only allow participants to wear one at a time. Therefore, you must choose which one you wish to receive at this time.
        PLEASE_SELECT_ONE                                                      = 7670,  -- Please select one... %. %.
        YOU_ARE_CURRENTLY_WEARING_IF_YOU_WISH_TO                               = 7671,  -- You are currently wearing %. If you wish to accept the chevron you earned this match, you must return the one you currently possess.
        ACCEPT_THE_YES_NO                                                      = 7672,  -- Accept the %? Yes. No.
