        WELL_I_M_SURE_NO                                                       = 7675,  -- Well? I'm sure. No.
        AS_LONG_AS_YOU_ARE_IN_POSSESSION_OF                                    = 7676,  -- As long as you are in possession of the %, you will bear the aforementioned title while participating in Ballista.
        UPON_THE_CHANCE_ANOTHER_CONTESTANT_CHECKS_YOU_DURING                   = 7677,  -- Upon the chance another contestant checks you during a match, not only will he be able to see your title, but also the total number of chevrons you have accumulated in your battles.
        FINALLY_THE_OFFICIAL_RULES_OF_BALLISTA_STATE_THAT                      = 7678,  -- Finally, the official rules of Ballista state that after a set period of time, you are required to return any chevrons received. When that time has come, a Herald will collect your chevrons at the time of entry into a new match.
        CONGRATULATIONS_BALLISTA_POINT_RANKING_REGISTRATION_FOR_THE_PREVIOUS_2 = 7679,  -- Congratulations! Ballista Point Ranking registration for the previous match has come to a close, and you have once again been deemed the most valuable player! You are a fine example to Conflict participants across Vana'diel! Keep up the fine work, %!
        YOU_HAVE_ALREADY_CONFIRMED_YOUR_DATA_FOR_THE                           = 7680,  -- You have already confirmed your data for the [/Jugner Forest/Pashhow Marshlands/Meriphataud Mountains] match. We look forward to your participation in future matches!
        YOU_HAVE_BEEN_REWARDED_WITH                                            = 7681,  -- You have been rewarded with %!
