        I_HAVE_FINISHED_REGISTERING_YOUR_DATA_YOUR_FINAL                       = 7686,  -- I have finished registering your data. Your final Ballista Point Ranking for the previous match is: #.
        I_REGISTERED_YOUR_POINT_TOTAL_HOWEVER_IT_SEEMS                         = 7687,  -- I registered your point total; however, it seems you did not make the final list. But do not fret. You will have many chances to redeem yourself in future matches. Good luck, %!
        YOUR_FINAL_BALLISTA_POINT_RANKING_FOR_THE_PREVIOUS                     = 7688,  -- Your final Ballista Point Ranking for the previous match is: #. (Rank among [/warriors/monks/white mages/black mages/red mages/thieves/paladins/dark knights/beastmasters/bards/rangers/samurais/ninjas/dragoons/summoners/blue mages/corsairs/puppetmasters/dancers/scholars/geomancers/rune fencers]: #) However, a little more practice, and the champion's throne is yours for the taking!
        I_AM_SORRY_BUT_WE_ARE_NO_LONGER                                        = 7689,  -- I am sorry, but we are no longer accepting Ballista Point Ranking registrations for the match in which you previously participated.
        FOR_FUTURE_REFERENCE_PLEASE_NOTE_THAT_THE_REGISTRATION                 = 7690,  -- For future reference, please note that the registration period is exactly four hours (Vana'diel time) from the close of each Ballista match.
        I_APOLOGIZE_BUT_IT_SEEMS_THAT_I_AM                                     = 7691,  -- I apologize, but it seems that I am having a bit of trouble trying to find the ranking list. Please come back later.
        I_APOLOGIZE_BUT_IT_SEEMS_THAT_I_AM_2                                   = 7692,  -- I apologize, but it seems that I am having a bit of trouble registering your data. Please come back in a few moments.
        YOU_HAVE_ALREADY_REGISTERED_YOUR_BALLISTA_POINTS_FOR                   = 7693,  -- You have already registered your Ballista Points for the previous match. Your current rank is #.
        VXE_O_O_W_U_W_UO_W                                                     = 7694,  -- VXe:#@o^:# %o^W u:# /W uo^:#@W uJ) %J:# o^BP:#@IME:#
        FOBO_HB                                                                = 7695,  -- fobO%hB
        ENDPARA                                                                = 7696,  -- endpara=#
        WHAT_DO_YOU_WISH_TO_KNOW_ABOUT_BASIC                                   = 7697,  -- What do you wish to know about? Basic rules. About the Petra. About Sprint. About Scout. About Gate Breach. About area-specific rules. About returning to battle. About special rules. Nothing at the moment.
        BALLISTA_IS_AN_EXERCISE_ONCE_USED_BY_THE                               = 7698,  -- Ballista is an exercise once used by the San d'Orian armies to train the Royal Knights in the art of the siege. The word ballista means to throw a stone, and the game has been a part of Vana'dielian military history for centuries.
        THE_RULES_ARE_SIMPLE_BALLISTA_IS_PLAYED_BY                             = 7699,  -- The rules are simple. Ballista is played by two teams over a number of hours (Vana'diel time). The team with the most points at the end of the match is the victor.
        PLAYERS_FROM_BOTH_TEAMS_MUST_SEARCH_FOR_PETRAS                         = 7700,  -- Players from both teams must search for Petras that a Herald has buried in various locations across the battlefield. The players must then take these stones and throw them into targets known as Rooks.
        THESE_ROOKS_CAN_APPEAR_IN_VARIOUS_LOCATIONS_AROUND                     = 7701,  -- These Rooks can appear in various locations around the battlefield, and both teams are allowed to throw their Petras into them.
        FINALLY_A_PLAYER_S_STRENGTH_IS_ADJUSTED_DEPENDING                      = 7702,  -- Finally, a player's strength is adjusted depending on his or her level. It is felt that this ultimately allows for a more balanced battle.
        PETRAS_CAN_BE_BURIED_ANYWHERE_ONCE_A_PLAYER                            = 7703,  -- Petras can be buried anywhere. Once a player believes he or she has found one, the Quarry (/quarry) command should be used to dig up the area at his or her feet.
        SOMETIMES_A_PLAYER_MAY_FIND_ITEMS_OTHER_THAN                           = 7704,  -- Sometimes a player may find items other than Petras, such as potions. These temporary items can only be used during the current match (or Best of Three series).
        PLAYERS_CAN_CARRY_MORE_THAN_ONE_PETRA_BUT                              = 7705,  -- Players can carry more than one Petra, but they cannot throw the stones away once they have obtained them. However, players will lose their Petras if they: (1) Successfully throw them into a rook. (2) Leave the area. (3) Are knocked out.
        BUT_DON_T_FORGET_A_PLAYER_WILL_BE                                      = 7706,  -- But don't forget, a player will be unable to use the Sprint command while in possession of a Petra. And, players can only use the Scout command if they carry one of the stones.
        AS_ONE_CAN_SEE_CAREFUL_PLANNING_AND_IMPECCABLE                         = 7707,  -- As one can see, careful planning and impeccable timing are the keys to victory.
        ALL_PARTICIPANTS_OF_BALLISTA_WILL_HAVE_THE_ABILITY                     = 7708,  -- All participants of Ballista will have the ability to use the Sprint command. This will temporarily increase one's movement speed, creating a better chance to find and obtain Petras.
        HOWEVER_REMEMBER_THAT_ONCE_A_PLAYER_HAS_OBTAINED                       = 7709,  -- However, remember that once a player has obtained a Petra, he or she will be unable to use the Sprint command. In its place, though, one may use the Scout command.
        THE_LOCATIONS_OF_THE_ROOKS_ARE_CONSTANTLY_CHANGING                     = 7710,  -- The locations of the Rooks are constantly changing. This makes it quite difficult to find the targets by just randomly walking about the area.
        COMMUNICATION_WITH_ONE_S_TEAM_MEMBERS_IS_OF                            = 7711,  -- Communication with one's team members is, of course, one way to locate Rooks. However, another way is by using the Scout command. This will inform a player of the approximate location of the nearest Rook.
        FINALLY_SCOUT_CAN_ONLY_BE_USED_WHEN_A                                  = 7712,  -- Finally, Scout can only be used when a player is carrying a Petra. Because Sprint cannot be used at this time, players must be weary of approaching enemies.
        SO_A_PETRA_HAS_BEEN_OBTAINED_AND_A                                     = 7713,  -- So, a Petra has been obtained and a Rook located. Now all that's left is tossing the stone in, right? Wrong.
        THERE_IS_ONE_ASPECT_OF_BALLISTA_THAT_HAS                               = 7714,  -- There is one aspect of Ballista that has yet to be mentioned...and this is where the real battle begins.
        TO_THROW_A_PETRA_INTO_A_ROOK_A                                         = 7715,  -- To throw a Petra into a Rook, a player must first wait until the Rook's gate is open. This takes impeccable timing, as the gate is only open for a short while.
        BUT_NOT_JUST_ANYONE_CAN_SCORE_POINTS_THIS                              = 7716,  -- But not just anyone can score points this way. A player must first take down a member of the opposing team and achieve Gate Breach status. Only then will his or her shots count.
        THIS_EXTREME_METHOD_OF_COMBAT_IS_WHAT_MADE                             = 7717,  -- This extreme method of combat is what made the ancient game of Ballista famous, and transformed its participants into heroes.
        RUNNING_ABOUT_LOOKING_FOR_STONES_IS_NO_DIFFERENT                       = 7718,  -- Running about looking for stones is no different from a child's game of hide-and-seek. Knowing when to strike is what separates the men from the boys.
        THE_FOLLOWING_MATCH_TYPES_ARE_AREA_SPECIFIC_ALL                        = 7719,  -- The following match types are area-specific: All or Nothing (one match) * Normal Items Allowed: Jugner Forest All or Nothing (one match) * Normal Items Restricted: Pashhow Marshlands Best of Three (three matches) * Normal Items Allowed: Meriphataud Mountains
        BEST_OF_THREE_SERIES_RULES_ARE_AS_FOLLOWS                              = 7720,  -- Best of Three series rules are as follows: Winning a match will earn a nation one match point. The nation with the most match points at the end of the series will be declared the victor. Winning the third and final match and producing the high scorer will result in two match points awarded. This allows both sides the chance for come-from-behind victories.
        BETWEEN_EACH_OF_THE_MATCHES_A_SHORT_INTERVAL                           = 7721,  -- Between each of the matches, a short interval will be implemented. During this interval, Invisible and Sneak will be cast on all participants. We suggest this time be used to discuss strategies with the other members of your nation's forces.
        PLAYERS_WILL_BE_FORBIDDEN_FROM_USING_ANY_ITEMS                         = 7722,  -- Players will be forbidden from using any items they bring to the battlefield. Only temporary items that are quarried may be used. A total of fifteen temporary items (though only one of each type) can be carried.
        WHEN_THIS_RULE_IS_IN_EFFECT_ALL_PLAYERS                                = 7723,  -- When this rule is in effect, all players will be presented with five complimentary temporary items at the beginning of the match.
        FOR_MORE_INFORMATION_ON_TEMPORARY_ITEMS_REFER_TO                       = 7724,  -- For more information on temporary items, refer to the special rules.
        AFTER_BEING_KO_D_IF_A_PLAYER_CHOOSES                                   = 7725,  -- After being KO'd, if a player chooses to be revived at the spot he was defeated, 100% of all HP and 50% of all MP will be restored. In addition, the player will maintain 50% of the TP he had earned.
        IF_A_PLAYER_CHOOSES_TO_RETURN_TO_THEIR                                 = 7726,  -- If a player chooses to return to their force's camp, HP and MP will be fully restored, but all TP will be lost.
        PLEASE_NOTE_THAT_MANY_OF_THE_RULES_PREVIOUSLY                          = 7727,  -- Please note that many of the rules previously considered special have been fully implemented. Also, several new special rules have been added.
        LEARN_ABOUT_WHICH_SPECIAL_RULES_TEMPORARY_ITEMS_BALLISTA               = 7728,  -- Learn about which special rules? Temporary items. Ballista Points. Scoring restrictions. Gate Breach radius expansion. Resistance to Sleep. Open entries. Minimum level restrictions. Re-entry restrictions. Participant & Rook numbers. Experience Points. Return.
        PREVIOUSLY_PARTICIPANTS_IN_BALLISTA_WERE_REQUIRED_TO_USE               = 7729,  -- Previously, participants in Ballista were required to use an item the moment they dug it up using the /quarry command. However, players can now stock these items as temporary items for use at any time during the match.
        PLAYERS_CAN_HOLD_UP_TO_TEN_TEMPORARY_ITEMS                             = 7730,  -- Players can hold up to ten temporary items, but only one of each type. If a player finds an item that they already possess, they must use it immediately or throw it away.
        IF_PLAYERS_WHO_POSSESS_TEN_TEMPORARY_ITEMS_FIND                        = 7731,  -- If players who possess ten temporary items find an item that they have not already obtained, they will also have the option to exchange it with one of their current items.
        ALSO_PLAYERS_WILL_NOT_AT_ANY_TIME_BE                                   = 7732,  -- Also, players will not, at any time, be allowed to trade temporary items. However, there are items that can be used on other Ballista participants. Please note that players may not be able to use these special items as soon as they are quarried.
        FINALLY_THE_HERALDS_WILL_COLLECT_TEMPORARY_ITEMS_WHEN                  = 7733,  -- Finally, the Heralds will collect temporary items when the match (the third in a Best of Three series) has concluded.
        BALLISTA_POINTS_ARE_REWARDED_TO_EACH_COMPETITOR_BASED                  = 7734,  -- Ballista Points are rewarded to each competitor based on his or her performance in a single Ballista match. The maximum number of points that can be accumulated per match is #.
        WHILE_IT_IS_TAKEN_INTO_CONSIDERATION_SCORING_PETRAS                    = 7735,  -- While it is taken into consideration, scoring Petras is not the only way to earn Ballista Points. Assisting allies and defeating members of the enemy forces can also earn a high score.
        BALLISTA_POINTS_CAN_BE_TRADED_FOR_SPECIAL_VOUCHERS                     = 7736,  -- Ballista Points can be traded for special vouchers, which may be exchanged for free temporary items at the start of new matches.
        HOWEVER_REMEMBER_THAT_DEPENDING_ON_THE_LEVEL_RESTRICTION               = 7737,  -- However, remember that depending on the level restriction of the match, certain vouchers will not be redeemed at the beginning of a match. Speak with a Marshal directly after a match to register your points.
        PLAYERS_WILL_ONLY_BE_ALLOWED_TO_SCORE_UP                               = 7738,  -- Players will only be allowed to score up to five Petras at a time. Also, a player's Gate Breach status will be automatically disengaged if a Petra is not scored within a certain amount of time. The amount of time is increased for those members of the team currently behind in points.
        ALL_ALLIES_WITHIN_A_CERTAIN_RADIUS_WILL_ACHIEVE                        = 7739,  -- All allies within a certain radius will achieve Gate Breach status when a member of the enemy forces is defeated.
        PLAYERS_RESISTANCE_TO_SLEEP_WILL_BE_INCREASED                          = 7740,  -- Players' resistance to sleep will be increased.
        DURING_THE_ENTRY_PERIOD_FROM_ALL_ADVENTURERS_WILL                      = 7741,  -- During the entry period, from #:, all adventurers will be allowed to join the forces with the smallest number of participants, regardless of allegiance. Open entries will be accepted until both sides have reached maximum capacity.
        IN_ORDER_TO_ENSURE_BALANCED_MATCHES_THE_FOLLOWING                      = 7742,  -- In order to ensure balanced matches, the following level limits are enforced: Level 30 matches: 1`30
        LEVEL_40_MATCHES_31_40_LEVEL_50_MATCHES                                = 7743,  -- Level 40 matches: 31`40 Level 50 matches: 41`50 Level 60 matches: 51`60 Unrestricted matches: 61`
        PLEASE_NOTE_THAT_ANY_PARTICIPANT_WHO_CANCELS_HIS                       = 7744,  -- Please note that any participant who cancels his or her registration will not be allowed to re-apply for the same match.
        WHEN_THE_TOTAL_NUMBER_OF_PARTICIPANTS_IN_A                             = 7745,  -- When the total number of participants in a match is less than 40, the location of the two camps will be adjusted. Also in this case, the number of Rooks will be reduced to two.
        ANY_ADVENTURER_WHOSE_MAIN_LEVEL_IS_OVER_30                             = 7746,  -- Any adventurer whose main level is over 30 will receive EXP for participating in a Ballista match. However, no EXP will be rewarded if the adventurer fails to actively take part in the match.
        READ_WHICH_CHAPTER_ON_B_P_RANKING_BASIC                                = 7747,  -- Read which chapter on B.P. Ranking? Basic Information. Registering Points. Rewards. Chevron & Title List. None.
        BALLISTA_POINT_RANKING_IS_BASED_UPON_ALL_BALLISTA                      = 7748,  -- Ballista Point Ranking is based upon all Ballista Points registered from the past ten matches in each of the three participating battle areas.
        ANYONE_WHO_WISHES_TO_TAKE_PART_IN_THE                                  = 7749,  -- Anyone who wishes to take part in the ranking needs to register his/her] points within four hours (Vana'diel time) from the end of the previous match.
        AFTER_THE_REGISTRATION_PERIOD_ENDS_PLAYERS_CAN_COMPARE                 = 7750,  -- After the registration period ends, players can compare their record with those of the previous nine matches.
        IF_AT_ANY_TIME_A_PLAYER_RANKS_IN                                       = 7751,  -- If, at any time, a player ranks in the top ten (overall) or first for a specific job, he/she] will have the opportunity to receive a special chevron as well as a new title.
        THERE_ARE_FOUR_TYPES_OF_CHEVRONS_AND_TITLES                            = 7752,  -- There are four types of chevrons and titles awarded to top-ten players (gold/mythril/silver/bronze), as well as twenty-two different types awarded for outstanding performances by players of each of the twenty-two jobs.
        WEARING_A_CHEVRON_DURING_A_BALLISTA_MATCH_WILL                         = 7753,  -- Wearing a chevron during a Ballista match will automatically change a player's current title. If a player wishes to possess this title after a match as well, he/she] must contact a certain bard in San d'Oria.
        ALSO_WHILE_WEARING_A_CHEVRON_PLAYERS_WILL_BE                           = 7754,  -- Also, while wearing a chevron, players will be able to trade Ballista Points for temporary items not available to all players.
        HOWEVER_THE_RULES_OF_BALLISTA_STATE_THAT_PLAYERS                       = 7755,  -- However, the rules of Ballista state that players may only possess a certain chevron for no longer than one half Vana'diel year. When that time comes, they are required to return the chevron before being allowed to participate in any further matches.
        FINALLY_CHECKING_SOMEONE_DURING_A_BALLISTA_MATCH_WILL                  = 7756,  -- Finally, checking someone during a Ballista match will display the total number of chevrons that person has accumulated to date.
        VIEW_WHICH_CHEVRON_TITLE_1ST_OVERALL_2ND_OVERALL                       = 7757,  -- View which chevron/title? 1st (overall). 2nd (overall). 3rd (overall). 4th-10th (overall). 1st (warrior). 1st (monk). 1st (white mage). 1st (black mage). 1st (red mage). 1st (thief). 1st (paladin). 1st (dark knight). 1st (beastmaster). 1st (bard). 1st (ranger). 1st (samurai). 1st (ninja). 1st (dragoon). 1st (summoner). 1st (blue mage). 1st (corsair). 1st (puppetmaster). 1st (dancer). 1st (scholar). 1st (geomancer). 1st (rune fencer). Return.
        KEY_ITEM_TITLE_GOLD_BALLITAR                                           = 7758,  -- Key Item: % Title: Gold Ballitar
        KEY_ITEM_TITLE_MYTHRIL_BALLITAR                                        = 7759,  -- Key Item: % Title: Mythril Ballitar
        KEY_ITEM_TITLE_SILVER_BALLITAR                                         = 7760,  -- Key Item: % Title: Silver Ballitar
        KEY_ITEM_TITLE_BRONZE_BALLITAR                                         = 7761,  -- Key Item: % Title: Bronze Ballitar
