        KEY_ITEM_TITLE_SABLETAR                                                = 7765,  -- Key Item: % Title: Sabletar
        KEY_ITEM_TITLE_SCARLETTAR                                              = 7766,  -- Key Item: % Title: Scarlettar
        KEY_ITEM_TITLE_SONICTAR                                                = 7767,  -- Key Item: % Title: Sonictar
        KEY_ITEM_TITLE_SAINTLYTAR                                              = 7768,  -- Key Item: % Title: Saintlytar
        KEY_ITEM_TITLE_SHADOWYTAR                                              = 7769,  -- Key Item: % Title: Shadowytar
        KEY_ITEM_TITLE_SAVAGETAR                                               = 7770,  -- Key Item: % Title: Savagetar
        KEY_ITEM_TITLE_SINGINGTAR                                              = 7771,  -- Key Item: % Title: Singingtar
