        ALRIGHT_THEN_TAKE_THIS_AND_GET_TO_WORK                                 = 7857,  -- Alright then! Take this % and get to work on those vile villains! I'll be preparing your special reward, kupo!
        EQUIP_THIS_AND_HAVE_A_NOMAD_MOOGLE_OUTSIDE                             = 7858,  -- Equip this %, and have a nomad moogle outside town cast special moogle magic upon it. Be sure to absorb as much malice as you can from those scoundrels, kupo!
        GOOD_JOB_KUPO_YOU_SURE_SHOWED_THEM_WHO                                 = 7859,  -- Good job, kupo! You sure showed them who's boss! Thanks to you, we were able to avoid a diplomatic disaster with the Far East, kupo.
        A_HANDFUL_OF_NO_GOOD_NOMAD_MOOGLES_AND                                 = 7860,  -- A handful of no-good nomad moogles and Goblins were conspiring to take over the MHMU, wilfully assuming false identities in order to obtain the armor and frame us, kupo!
        THEN_THEY_HIRED_THIEVES_TO_WEAR_THE_ARMOR                              = 7861,  -- Then, they hired thieves to wear the armor and do their dirty work!
        BUT_THANKS_TO_ALL_YOU_COURAGEOUS_ADVENTURERS_THE                       = 7862,  -- But thanks to all you courageous adventurers, the MHMU is safe and sound, kupo!
